TaskPoolManager = {}
TaskPoolManager.TaskPools = {}

function TaskPoolManager:putTaskIntoPool(task)
    if self.TaskPools[task.TaskPoolId] == nil then
        self.TaskPools[task.TaskPoolId] = {}
    end
    table.insert(self.TaskPools[task.TaskPoolId], { Id = task.Id, Weight = task.Weight })
end

function TaskPoolManager:getTaskIdsFromRegularPool(poolid)
    local data = {}
    if self.TaskPools[poolid] ~= nil then
        for _, task in pairs(self.TaskPools[poolid]) do
            table.insert(data, task.Id)
        end
    end
    return data
end

function TaskPoolManager:getTaskIdsFromRandomPool(poolid, taskCount)
    local data = {}
    if self.TaskPools[poolid] ~= nil then
        local randomPoolData = table.merge({}, self.TaskPools[poolid])
        math.randomseed(tostring(os.time()):reverse():sub(1, 7))
        for i = 1, taskCount do
            local rs = math.random(0, self:getSumOfWeight(randomPoolData))
            for key, task in pairs(randomPoolData) do
                rs = rs - task.Weight
                if rs < 0 then
                    table.insert(data, task.Id)
                    table.remove(randomPoolData, key)
                    break
                end
            end
        end
    end
    return data
end

function TaskPoolManager:getSumOfWeight(pooltable)
    local sumOfWeight = 0
    for _, task in pairs(pooltable) do
        sumOfWeight = sumOfWeight + task.Weight
    end
    return sumOfWeight
end

function table.merge(tDest, tSrc)
    for k, v in pairs(tSrc) do
        tDest[k] = v
    end
    return tDest
